import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Upload } from 'lucide-react';
import toast from 'react-hot-toast';

const FormField = ({ label, value, onChange, placeholder = "", dir = "ltr" }: any) => (
  <div className="space-y-1">
    <label className="text-[9px] font-black uppercase text-gray-500 ml-1">{label}</label>
    <input 
      value={value || ''} 
      onChange={(e) => onChange(e.target.value)}
      dir={dir}
      className="w-full bg-white/5 border border-white/10 p-3 rounded-xl text-xs text-white outline-none focus:border-primary transition-all"
      placeholder={placeholder}
    />
  </div>
);

const TextAreaField = ({ label, value, onChange, dir = "ltr" }: any) => (
  <div className="space-y-1">
    <label className="text-[9px] font-black uppercase text-gray-500 ml-1">{label}</label>
    <textarea 
      value={value || ''} 
      onChange={(e) => onChange(e.target.value)}
      dir={dir}
      className="w-full bg-white/5 border border-white/10 p-4 rounded-xl text-xs h-32 text-white outline-none focus:border-primary transition-all"
    />
  </div>
);

export const AdminArtworkForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('general');

  const [formData, setFormData] = useState({
    Artwork_ID: '',
    Student: '',
    Artist_ID: '',
    Artist_Name: '',
    Title_In_English: '',
    Title_In_Arabic: '',
    Series_ID: '',
    Year_Created: '',
    Year_Finished: '',
    Medium: '',
    Duration: '',
    Artwork_Description_In_English: '',
    Artwork_Description_In_Arabic: '',
    Cloudinary_Image_URL: '',
    Section_ID: '',
    Book_ID: '',
    Status: 'Complete'
  });

  useEffect(() => {
    if (id) {
      AdminService.getArtworkById(id).then((res: any) => {
        const data = res.data?.data;
        if (data) setFormData(data);
      }).catch(() => toast.error("Artwork record not found"));
    }
  }, [id]);

  const updateField = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertArtwork(formData);
      toast.success(id ? "Archive Updated" : "Artwork Cataloged");
      navigate('/admin/artworks');
    } catch (err) { toast.error("Cataloging Failed"); }
    finally { setLoading(false); }
  };

  return (
    <div className="max-w-6xl mx-auto p-6 space-y-8 animate-in fade-in duration-700">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-500 font-black text-[10px] uppercase tracking-widest hover:text-white transition-colors">
          <ArrowLeft size={14} /> Gallery
        </button>
        <div className="flex gap-2">
          {['general', 'description', 'archive'].map(tab => (
            <button 
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-primary text-black' : 'bg-white/5 text-gray-400 hover:bg-white/10'}`}
            >
              {tab}
            </button>
          ))}
        </div>
      </div>

      <form onSubmit={handleManualSubmit} className="bg-[#0f0f0f] border border-white/5 rounded-[2.5rem] shadow-2xl overflow-hidden">
        <div className="p-10">
          <h2 className="text-2xl font-black italic uppercase mb-8">{id ? 'Modify' : 'Catalog'} <span className="text-primary">Artwork</span></h2>
          
          {activeTab === 'general' && (
            <div className="grid grid-cols-2 gap-6 animate-in fade-in slide-in-from-right-4">
              <FormField label="Artwork ID" value={formData.Artwork_ID} onChange={(v: string) => updateField('Artwork_ID', v)} placeholder="AW000001" />
              <FormField label="Artist ID" value={formData.Artist_ID} onChange={(v: string) => updateField('Artist_ID', v)} placeholder="AR15" />
              <FormField label="Artist Name" value={formData.Artist_Name} onChange={(v: string) => updateField('Artist_Name', v)} />
              <FormField label="Title (EN)" value={formData.Title_In_English} onChange={(v: string) => updateField('Title_In_English', v)} />
              <FormField label="Title (AR)" value={formData.Title_In_Arabic} onChange={(v: string) => updateField('Title_In_Arabic', v)} dir="rtl" />
              <FormField label="Medium" value={formData.Medium} onChange={(v: string) => updateField('Medium', v)} />
              <FormField label="Year Created" value={formData.Year_Created} onChange={(v: string) => updateField('Year_Created', v)} />
              <FormField label="Status" value={formData.Status} onChange={(v: string) => updateField('Status', v)} />
            </div>
          )}

          {activeTab === 'description' && (
            <div className="space-y-6 animate-in fade-in slide-in-from-right-4">
              <FormField label="Cloudinary Image URL" value={formData.Cloudinary_Image_URL} onChange={(v: string) => updateField('Cloudinary_Image_URL', v)} />
              <TextAreaField label="Description (EN)" value={formData.Artwork_Description_In_English} onChange={(v: string) => updateField('Artwork_Description_In_English', v)} />
              <TextAreaField label="Description (AR)" value={formData.Artwork_Description_In_Arabic} onChange={(v: string) => updateField('Artwork_Description_In_Arabic', v)} dir="rtl" />
            </div>
          )}

          {activeTab === 'archive' && (
            <div className="grid grid-cols-2 gap-6 animate-in fade-in slide-in-from-right-4">
              <FormField label="Series ID" value={formData.Series_ID} onChange={(v: string) => updateField('Series_ID', v)} />
              <FormField label="Book ID" value={formData.Book_ID} onChange={(v: string) => updateField('Book_ID', v)} />
              <FormField label="Section ID" value={formData.Section_ID} onChange={(v: string) => updateField('Section_ID', v)} />
              <FormField label="Student Responsible" value={formData.Student} onChange={(v: string) => updateField('Student', v)} />
              <FormField label="Duration (Video/Film)" value={formData.Duration} onChange={(v: string) => updateField('Duration', v)} />
            </div>
          )}
        </div>

        <div className="bg-white/5 p-6 border-t border-white/5 flex justify-end">
          <button type="submit" disabled={loading} className="bg-primary text-black px-12 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-white transition-all">
            <Save size={18} className="inline mr-2" /> {id ? "Update Piece" : "Catalog Piece"}
          </button>
        </div>
      </form>
    </div>
  );
};
